'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './card.module.css'

export interface CardProps extends HTMLAttributes<HTMLDivElement> {
  variant?: 'default' | 'outlined' | 'elevated'
  padding?: 'none' | 'sm' | 'md' | 'lg'
}

export function Card({
  variant = 'default',
  padding = 'md',
  className,
  children,
  ...props
}: CardProps) {
  return (
    <div
      data-variant={variant}
      data-padding={padding}
      className={cn(styles['card'], className)}
      {...props}
    >
      {children}
    </div>
  )
}

export interface CardHeaderProps extends HTMLAttributes<HTMLDivElement> {}

export function CardHeader({ className, children, ...props }: CardHeaderProps) {
  return (
    <div className={cn(styles['header'], className)} {...props}>
      {children}
    </div>
  )
}

export interface CardTitleProps extends HTMLAttributes<HTMLHeadingElement> {}

export function CardTitle({ className, children, ...props }: CardTitleProps) {
  return (
    <h3 className={cn(styles['title'], className)} {...props}>
      {children}
    </h3>
  )
}

export interface CardContentProps extends HTMLAttributes<HTMLDivElement> {}

export function CardContent({ className, children, ...props }: CardContentProps) {
  return (
    <div className={cn(styles['content'], className)} {...props}>
      {children}
    </div>
  )
}

export interface CardFooterProps extends HTMLAttributes<HTMLDivElement> {}

export function CardFooter({ className, children, ...props }: CardFooterProps) {
  return (
    <div className={cn(styles['footer'], className)} {...props}>
      {children}
    </div>
  )
}

@layer cascivo.component {
  .card {
    background-color: var(--cascivo-color-surface);
    border-radius: var(--cascivo-radius-surface);
    overflow: hidden;
    padding: var(--_card-p, 0);

    &[data-padding='none'] {
      --_card-p: 0;
    }
    &[data-padding='sm'] {
      --_card-p: var(--cascivo-space-4);
    }
    &[data-padding='md'] {
      --_card-p: var(--cascivo-space-6);
    }
    &[data-padding='lg'] {
      --_card-p: var(--cascivo-space-8);
    }

    &[data-variant='default'] {
      border: 1px solid var(--cascivo-color-border);
    }

    &[data-variant='outlined'] {
      border: 1.5px solid var(--cascivo-color-border-strong);
    }

    &[data-variant='elevated'] {
      border: none;
      box-shadow: var(--cascivo-shadow-md);
    }
  }

  .header {
    padding: var(--_card-p, var(--cascivo-space-6));
    padding-block-end: 0;
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    /* Allow this flex section to shrink inside the card instead of forcing its
       content past the card's clipping edge (overflow: hidden above). */
    min-inline-size: 0;
  }

  .title {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-tight);
    margin: 0;
  }

  .content {
    padding: var(--_card-p, var(--cascivo-space-6));
    color: var(--cascivo-color-text-subtle);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-relaxed);
  }

  .footer {
    padding: var(--_card-p, var(--cascivo-space-6));
    padding-block-start: 0;
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    min-inline-size: 0;

    /* Let direct children (e.g. a label beside a status Badge) shrink below their
       intrinsic width so a long label doesn't push a trailing item past the card's
       clipping edge. A child that must not shrink can set flex-shrink: 0 itself. */
    & > * {
      min-inline-size: 0;
    }
  }
}
